const fs = require('fs');

const RULES_CSV_PATH = '/home/node/config/triage_rules.csv';
const defaultBillKeywords = [
  'bill', 'billing', 'invoice', 'statement', 'payment due', 'past due',
  'autopay', 'utility', 'electric', 'gas', 'water', 'internet',
  'phone bill', 'insurance', 'mortgage', 'rent', 'credit card', 'due date'
];
const requestKeywords = [
  'please', 'can you', 'could you', 'would you', 'need you', 'action required',
  'review', 'approve', 'sign', 'help', 'let me know', 'respond', 'reply',
  'asap', 'urgent', 'follow up'
];
const fundsInfoKeywords = [
  'received funds', 'you received funds', 'transfer settled', 'has settled',
  'payment is pending', 'scheduled payment is pending', 'payment posted',
  'payment completed', 'deposit received', 'withdrawal request initiated'
];

const parseCsv = (raw) => {
  const lines = String(raw || '').split(/\r?\n/).map((l) => l.trim()).filter((l) => l && !l.startsWith('#'));
  if (!lines.length) return [];
  const headers = lines[0].split(',').map((h) => h.trim().toLowerCase());
  return lines.slice(1).map((line) => {
    const cols = line.split(',');
    const row = {};
    headers.forEach((h, i) => { row[h] = (cols[i] || '').trim(); });
    return row;
  });
};

const escapeRegex = (value) => value.replace(/[.*+?^()|[\]\\]/g, '\\$&');
const containsKeyword = (text, keyword) => {
  const normalized = String(keyword || '').trim().toLowerCase();
  if (!normalized) return false;
  if (/^[a-z0-9]+$/i.test(normalized)) {
    return new RegExp('\\b' + escapeRegex(normalized) + '\\b', 'i').test(text);
  }
  return text.includes(normalized);
};

let rows = [];
try { rows = parseCsv(fs.readFileSync(RULES_CSV_PATH, 'utf8')); } catch (e) { rows = []; }

const importantDomains = new Set();
const importantEmails = new Set();
const billKeywords = new Set(defaultBillKeywords);
const spamDomains = new Set();
const spamSenders = new Set();

for (const row of rows) {
  const type = String(row.type || row.rule_type || row.kind || '').trim().toLowerCase();
  const value = String(row.value || row.pattern || row.entry || '').trim().toLowerCase();
  if (!type || !value) continue;
  if (type === 'domain') importantDomains.add(value);
  else if (type === 'email') importantEmails.add(value);
  else if (type === 'bill_keyword' || type === 'keyword' || type === 'bill') billKeywords.add(value);
  else if (type === 'spam_domain') spamDomains.add(value);
  else if (type === 'spam_sender' || type === 'spam_email') spamSenders.add(value);
}

const fromField = item.json.from || item.json.From || item.json.sender || item.json.email || '';
const senderRaw = typeof fromField === 'string' ? fromField : (fromField?.emailAddress?.address || fromField?.emailAddress?.name || '');
const emailMatch = String(senderRaw).match(/[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}/);
const senderEmail = (emailMatch ? emailMatch[0] : String(senderRaw)).toLowerCase();
const senderDomain = senderEmail.includes('@') ? senderEmail.split('@').pop() : '';
const subject = String(item.json.subject || item.json.Subject || item.json.snippet || '');
const body = String(item.json.textPlain || item.json.body || item.json.snippet || item.json.bodyPreview || '');
const content = (subject + '\n' + body).toLowerCase();
const mentionsAntonio = content.includes('antonio');
const directRequestDetected = requestKeywords.some((keyword) => containsKeyword(content, keyword));
const fundsInfoDetected = fundsInfoKeywords.some((keyword) => containsKeyword(content, keyword));
const importantEmailMatch = senderEmail && importantEmails.has(senderEmail);
const importantDomainMatch = senderDomain && Array.from(importantDomains).some((d) => senderDomain === d || senderDomain.endsWith('.' + d));
const spamSenderMatch = senderEmail && spamSenders.has(senderEmail);
const spamDomainMatch = senderDomain && Array.from(spamDomains).some((d) => senderDomain === d || senderDomain.endsWith('.' + d));
const billDetected = Array.from(billKeywords).some((keyword) => containsKeyword(content, keyword));
const billEscalationDetected = billDetected && directRequestDetected && mentionsAntonio;
const forceSpam = spamSenderMatch || spamDomainMatch;
const forceImportant = !forceSpam && (importantEmailMatch || importantDomainMatch || billEscalationDetected);

const reasons = [];
if (spamSenderMatch) reasons.push('spam_sender');
if (spamDomainMatch) reasons.push('spam_domain');
if (billDetected) reasons.push('bill_keyword');
if (importantEmailMatch) reasons.push('important_email');
if (importantDomainMatch) reasons.push('important_domain');
if (billEscalationDetected) reasons.push('bill_escalation');
if (fundsInfoDetected) reasons.push('funds_info');

item.json.sender_email = senderEmail;
item.json.sender_domain = senderDomain;
item.json.subject_normalized = subject;
item.json.body_normalized = body;
item.json._triage = {
  bill_detected: billDetected,
  bill_escalation_detected: billEscalationDetected,
  funds_info_detected: fundsInfoDetected,
  direct_request_detected: directRequestDetected,
  important_list_match: importantEmailMatch || importantDomainMatch,
  spam_detected: forceSpam,
  force_spam: forceSpam,
  force_important: forceImportant,
  rule_reason: reasons.join(',') || ''
};

return item;
